// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Budget {

    //  Roles 

    address public owner;

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized. Only owner can do this.");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    //  Reentrancy Guard 

    bool private locked;

    modifier noReentrant() {
        require(!locked, "Reentrant call.");
        locked = true;
        _;
        locked = false;
    }

    //  Project & Phase Structs 

    enum PhaseStatus { Pending, ProofSubmitted, Released }

    struct Phase {
        string name;
        uint budget;          // Amount (in wei) allocated to this phase
        string evidenceCID;   // IPFS CID uploaded by contractor (bills, receipts, photos)
        PhaseStatus status;
    }

    struct Project {
        uint id;
        string name;
        address payable contractor;
        uint startTime;
        uint endTime;
        uint currentPhase;
        bool exists;
        Phase[] phases;
    }

    mapping(uint => Project) public projects;
    uint public projectCount;

    //  Events 

    event FundsReceived(address from, uint amount);
    event ProjectCreated(uint indexed projectId, string name, address contractor);
    event AddTimeline(uint indexed projectId, uint start, uint end);  // Fixed: param types added
    event PhaseProofSubmitted(uint indexed projectId, uint phaseIndex, string evidenceCID);
    event PhaseReleased(uint indexed projectId, uint phaseIndex, uint amount, address contractor);

    //  Funding 

    receive() external payable {
        emit FundsReceived(msg.sender, msg.value);
    }

    function getBalance() public view returns (uint) {
        return address(this).balance;
    }

    //  Project Management 

    function createProject(
        string memory _name,
        address payable _contractor,
        uint _startTime,
        uint _endTime,
        string[] memory _phaseNames,
        uint[] memory _phaseBudgets
    ) public payable onlyOwner {
        require(_phaseNames.length == _phaseBudgets.length, "Phase names and budgets must match.");
        require(_phaseNames.length > 0, "Must have at least one phase.");
        require(_startTime < _endTime, "Start must be before end.");

        uint total = 0;
        for (uint i = 0; i < _phaseBudgets.length; i++) {
            total += _phaseBudgets[i];
        }
        require(msg.value == total, "ETH sent must equal total phase budgets.");

        projectCount++;
        Project storage p = projects[projectCount];
        p.id = projectCount;
        p.name = _name;
        p.contractor = _contractor;
        p.startTime = _startTime;
        p.endTime = _endTime;
        p.currentPhase = 0;
        p.exists = true;

        for (uint i = 0; i < _phaseNames.length; i++) {
            p.phases.push(Phase({
                name: _phaseNames[i],
                budget: _phaseBudgets[i],
                evidenceCID: "",
                status: PhaseStatus.Pending
            }));
        }

        emit ProjectCreated(projectCount, _name, _contractor);
        emit AddTimeline(projectCount, _startTime, _endTime);
    }

    //  Phase-Gated Fund Release

    function submitPhaseProof(uint _projectId, string memory _evidenceCID) public {
        Project storage p = projects[_projectId];
        require(p.exists, "Project does not exist.");
        require(msg.sender == p.contractor, "Only the contractor can submit proof.");
        require(p.currentPhase < p.phases.length, "All phases already completed.");

        Phase storage phase = p.phases[p.currentPhase];
        require(phase.status == PhaseStatus.Pending, "Proof already submitted for this phase.");

        phase.evidenceCID = _evidenceCID;
        phase.status = PhaseStatus.ProofSubmitted;

        emit PhaseProofSubmitted(_projectId, p.currentPhase, _evidenceCID);
    }

    function releasePhase(uint _projectId) public onlyOwner noReentrant {
        Project storage p = projects[_projectId];
        require(p.exists, "Project does not exist.");
        require(p.currentPhase < p.phases.length, "All phases already completed.");

        Phase storage phase = p.phases[p.currentPhase];
        require(phase.status == PhaseStatus.ProofSubmitted, "No proof submitted for this phase yet.");
        require(address(this).balance >= phase.budget, "Insufficient contract balance.");

        phase.status = PhaseStatus.Released;
        uint amount = phase.budget;
        uint phaseIndex = p.currentPhase;
        p.currentPhase++;

        (bool success, ) = p.contractor.call{value: amount}("");
        require(success, "Transfer failed.");

        emit PhaseReleased(_projectId, phaseIndex, amount, p.contractor);
    }

    // ─── Public Getter (for the citizen budget tracking page) ─────────────────

    function getPhases(uint _projectId) public view returns (
        string[] memory names,
        uint[] memory budgets,
        string[] memory evidenceCIDs,
        PhaseStatus[] memory statuses
    ) {
        Project storage p = projects[_projectId];
        require(p.exists, "Project does not exist.");

        uint len = p.phases.length;
        names       = new string[](len);
        budgets     = new uint[](len);
        evidenceCIDs = new string[](len);
        statuses    = new PhaseStatus[](len);

        for (uint i = 0; i < len; i++) {
            names[i]        = p.phases[i].name;
            budgets[i]      = p.phases[i].budget;
            evidenceCIDs[i] = p.phases[i].evidenceCID;
            statuses[i]     = p.phases[i].status;
        }
    }
}

contracts/Voting.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Voting {

    //  Roles

    address public admin;

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin can do this.");
        _;
    }

    constructor() {
        admin = msg.sender;
    }

    //  Election Timing 

    uint public startTime;
    uint public endTime;

    event ElectionTimeSet(uint startTime, uint endTime);

    function setElectionTime(uint _startTime, uint _endTime) public onlyAdmin {
        require(_startTime < _endTime, "Start must be before end.");
        require(_startTime > block.timestamp, "Start time must be in the future.");
        startTime = _startTime;
        endTime = _endTime;
        emit ElectionTimeSet(_startTime, _endTime);
    }

    modifier electionOpen() {
        require(block.timestamp >= startTime && block.timestamp <= endTime, "Election is not open.");
        _;
    }

    modifier electionClosed() {
        require(block.timestamp > endTime, "Election has not ended yet.");
        _;
    }

    //  Candidates

    struct Candidate {
        uint id;
        string name;
        string photoCID;   // IPFS CID for the candidate's photo
        uint voteCount;
    }

    mapping(uint => Candidate) public candidates;
    uint public candidatesCount;

    event CandidateAdded(uint indexed id, string name, string photoCID);

    function addCandidate(string memory _name, string memory _photoCID) public onlyAdmin {
        require(
            block.timestamp < startTime || startTime == 0,
            "Cannot add candidates after election has started."
        );
        candidatesCount++;
        candidates[candidatesCount] = Candidate(candidatesCount, _name, _photoCID, 0);
        emit CandidateAdded(candidatesCount, _name, _photoCID);
    }

    //  Voter Registration

    enum VoterStatus { NotRegistered, Pending, Verified, Rejected }

    mapping(address => VoterStatus) public voterStatus;
    mapping(address => string) public voterIdCID;  // IPFS CID of uploaded ID proof
    address[] public pendingVoters;                // So admin page can list requests

    event VoterRequested(address indexed voter, string idProofCID);
    event VoterApproved(address indexed voter);
    event VoterRejected(address indexed voter);

    function requestVoterRegistration(string memory _idProofCID) public {
        require(voterStatus[msg.sender] == VoterStatus.NotRegistered, "Already registered or pending.");
        voterStatus[msg.sender] = VoterStatus.Pending;
        voterIdCID[msg.sender] = _idProofCID;
        pendingVoters.push(msg.sender);
        emit VoterRequested(msg.sender, _idProofCID);
    }

    function approveVoter(address _voter) public onlyAdmin {
        require(voterStatus[_voter] == VoterStatus.Pending, "Voter is not pending.");
        voterStatus[_voter] = VoterStatus.Verified;
        emit VoterApproved(_voter);
    }

    function rejectVoter(address _voter) public onlyAdmin {
        require(voterStatus[_voter] == VoterStatus.Pending, "Voter is not pending.");
        voterStatus[_voter] = VoterStatus.Rejected;
        emit VoterRejected(_voter);
    }

    function getPendingVoters() public view returns (address[] memory) {
        return pendingVoters;
    }
 //Voting

    mapping(address => bool) public hasVoted;

    event VotedEvent(uint indexed candidateId, address indexed voter);

    function vote(uint _candidateId) public electionOpen {
        require(voterStatus[msg.sender] == VoterStatus.Verified, "You are not a verified voter.");
        require(!hasVoted[msg.sender], "You have already voted.");
        require(_candidateId > 0 && _candidateId <= candidatesCount, "Invalid candidate ID.");

        hasVoted[msg.sender] = true;
        candidates[_candidateId].voteCount++;

        emit VotedEvent(_candidateId, msg.sender);
    }

    //  Results 

    bool public resultsDeclared;
    uint public winnerId;

    event ResultsDeclared(uint indexed winnerId, string winnerName, uint voteCount);

    function declareResult() public onlyAdmin electionClosed {
        require(!resultsDeclared, "Results already declared.");
        require(candidatesCount > 0, "No candidates.");

        uint highestVotes = 0;
        uint winningId = 0;

        for (uint i = 1; i <= candidatesCount; i++) {
            if (candidates[i].voteCount > highestVotes) {
                highestVotes = candidates[i].voteCount;
                winningId = i;
            }
        }

        resultsDeclared = true;
        winnerId = winningId;

        emit ResultsDeclared(winningId, candidates[winningId].name, highestVotes);
    }

    function getWinner() public view returns (string memory name, string memory photoCID, uint voteCount) {
        require(resultsDeclared, "Results have not been declared yet.");
        Candidate memory w = candidates[winnerId];
        return (w.name, w.photoCID, w.voteCount);
    }
}

